CREATE VIEW public.emission_full_results AS
 SELECT i.seq_no,
    i.activity_id AS requested_activity_id,
    i.requested_region,
    i.requested_year,
    i.input_type,
    i.input_value,
    i.input_unit,
    i.passengers,
    o.success,
    o.co2e,
    o.co2e_unit,
    o.total_tco2e,
    o.factor_name,
    o.factor_activity_id,
    o.factor_source,
    o.source_dataset,
    o.factor_year,
    o.factor_region,
    o.factor_category,
    o.source_lca_activity,
    o.co2e_total,
    o.co2,
    o.ch4,
    o.n2o,
    o.gas_breakdown_available,
    o.error_code,
    o.error_message
   FROM (public.emission_calculation_inputs i
     LEFT JOIN public.emission_calculation_outputs o ON ((o.input_id = i.id)))
  ORDER BY i.seq_no;


